big-bang.stylesCss:
/* ck-style-module:dieter-tokens-tokens.css */
@import "/dieter/tokens/tokens.css";
/* ck-style-module:end */

/* ck-style-module:dieter-components-button-button.css */
@import "/dieter/components/button/button.css";
/* ck-style-module:end */

/* ck-style-module:shared-header.css */
.ck-headerLayout {
  display: grid;
  gap: var(--ck-header-gap, var(--space-6));
}

.ck-headerLayout[data-has-header='false'] {
  grid-template-areas: 'body';
  gap: 0;
}

.ck-headerLayout[data-has-header='true'][data-header-placement='top'] {
  grid-template-areas:
    'header'
    'body';
}

.ck-headerLayout[data-has-header='true'][data-header-placement='bottom'] {
  grid-template-areas:
    'body'
    'header';
}

.ck-headerLayout[data-has-header='true'][data-header-placement='left'] {
  grid-template-columns: minmax(220px, 340px) minmax(0, 1fr);
  grid-template-areas: 'header body';
  align-items: start;
}

.ck-headerLayout[data-has-header='true'][data-header-placement='right'] {
  grid-template-columns: minmax(0, 1fr) minmax(220px, 340px);
  grid-template-areas: 'body header';
  align-items: start;
}

.ck-headerLayout > .ck-header {
  grid-area: header;
}

.ck-headerLayout > .ck-headerLayout__body {
  grid-area: body;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
}

.ck-header {
  display: grid;
  gap: var(--ck-header-inner-gap, var(--space-4));
}

.ck-header__text {
  display: flex;
  flex-direction: column;
  gap: var(--ck-header-text-gap, var(--space-2));
  min-width: 0;
}

.ck-header__title,
.ck-header__subtitle {
  margin: 0;
}

.ck-header__title {
  font-family: var(--typo-title-family, var(--font-ui));
  font-style: var(--typo-title-style, normal);
  font-weight: var(--typo-title-weight, 600);
  font-size: var(--typo-title-size, var(--fs-18));
  letter-spacing: var(--typo-title-tracking, 0em);
  line-height: var(--typo-title-line-height, var(--lh-tight));
  color: var(--typo-title-color, var(--color-system-black));
}

.ck-header__subtitle {
  font-family: var(--typo-body-family, var(--font-ui));
  font-style: var(--typo-body-style, normal);
  font-weight: var(--typo-body-weight, 400);
  font-size: var(--typo-body-size, var(--fs-14));
  letter-spacing: var(--typo-body-tracking, 0em);
  line-height: var(--typo-body-line-height, var(--lh-body));
  color: var(--typo-body-color, var(--color-system-black));
}

.ck-header__subtitle a {
  color: inherit;
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 2px;
}

.ck-header__subtitle[hidden] {
  display: none !important;
}

.ck-header[data-cta-placement='right'] {
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: center;
}

.ck-header[data-align='center'][data-cta-placement='right'] {
  grid-template-columns: auto auto;
  justify-content: center;
}

.ck-header[data-align='right'][data-cta-placement='right'] {
  grid-template-columns: auto auto;
  justify-content: end;
}

.ck-header[data-cta-placement='below'] {
  grid-template-columns: minmax(0, 1fr);
}

.ck-header[data-cta-placement='below'] > .ck-header__cta {
  justify-self: start;
}

.ck-header[data-align='center'][data-cta-placement='below'] > .ck-header__cta {
  justify-self: center;
}

.ck-header[data-align='right'][data-cta-placement='below'] > .ck-header__cta {
  justify-self: end;
}

.ck-header[data-align='center'] {
  text-align: center;
}

.ck-header[data-align='center'] > .ck-header__text {
  align-items: center;
}

.ck-header[data-align='right'] {
  text-align: right;
}

.ck-header[data-align='right'] > .ck-header__text {
  align-items: flex-end;
}

.ck-header__cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  align-self: center;
  gap: var(--control-inline-gap-sm, var(--space-2));
  padding-inline: var(--ck-header-cta-padding-inline, var(--space-4));
  padding-block: max(var(--ck-header-cta-padding-block, var(--space-3)), var(--space-2));
  border-radius: var(--ck-header-cta-radius, var(--control-radius-md));
  background: var(--ck-header-cta-bg, var(--color-system-blue));
  color: var(--ck-header-cta-fg, var(--color-system-white));
  border: var(--ck-header-cta-border-width, 0px) solid var(--ck-header-cta-border-color, transparent);
  text-decoration: none;
  font-family: var(--typo-button-family, var(--font-ui));
  font-style: var(--typo-button-style, normal);
  font-weight: var(--typo-button-weight, 600);
  font-size: var(--typo-button-size, var(--fs-14));
  letter-spacing: var(--typo-button-tracking, 0em);
  line-height: var(--typo-button-line-height, var(--lh-tight));
  white-space: nowrap;
}

.ck-header__cta[data-icon-placement='right'] {
  flex-direction: row-reverse;
}

.ck-header__ctaIcon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex: none;
  inline-size: var(--ck-header-cta-icon-size, var(--icon-size-16, 1rem));
  block-size: var(--ck-header-cta-icon-size, var(--icon-size-16, 1rem));
  background: currentColor;
  -webkit-mask-image: var(--ck-header-cta-icon);
  mask-image: var(--ck-header-cta-icon);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-position: center;
  mask-position: center;
  -webkit-mask-size: contain;
  mask-size: contain;
}

.ck-header__ctaIcon[hidden] {
  display: none !important;
}

.ck-header__ctaLabel {
  display: inline;
}

.ck-header__cta[aria-disabled='true'] {
  opacity: 0.55;
  pointer-events: none;
}

.ck-header__cta[hidden] {
  display: none !important;
}

@media (max-width: 900px) {
  .ck-headerLayout[data-has-header='true'][data-header-placement='left'],
  .ck-headerLayout[data-has-header='true'][data-header-placement='right'] {
    grid-template-columns: 1fr;
    grid-template-areas:
      'header'
      'body';
    align-items: stretch;
  }

  .ck-header__cta {
    max-width: 100%;
    white-space: normal;
  }

  .ck-header[data-cta-placement='right'] {
    grid-template-columns: minmax(0, 1fr);
    align-items: start;
  }

  .ck-header[data-cta-placement='right'] > .ck-header__cta {
    justify-self: start;
  }

  .ck-header[data-align='center'][data-cta-placement='right'] > .ck-header__cta {
    justify-self: center;
  }

  .ck-header[data-align='right'][data-cta-placement='right'] > .ck-header__cta {
    justify-self: end;
  }
}

/* ck-style-module:end */

/* ck-style-module:shared-localeSwitcher.css */
.ck-locale-switcher {
  position: absolute;
  z-index: 80;
  display: inline-flex;
  max-inline-size: min(220px, calc(100% - (var(--space-3) * 2)));
  color: var(--ck-locale-switcher-fg, var(--color-system-black));
}

.ck-locale-switcher[data-host='pod'] {
  --ck-locale-switcher-gap: var(--space-3);
}

.ck-locale-switcher[data-host='stage'] {
  --ck-locale-switcher-gap: var(--space-3);
}

.ck-locale-switcher[data-host='pod'][data-position='top-left'] {
  inset-block-start: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(-100% - var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='top-center'] {
  inset-block-start: 0;
  inset-inline-start: 50%;
  transform: translate(-50%, calc(-100% - var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='top-right'] {
  inset-block-start: 0;
  inset-inline-end: 0;
  transform: translate(0, calc(-100% - var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='right-middle'] {
  inset-block-start: 50%;
  inset-inline-end: 0;
  transform: translate(calc(100% + var(--ck-locale-switcher-gap)), -50%);
}

.ck-locale-switcher[data-host='pod'][data-position='bottom-right'] {
  inset-block-end: 0;
  inset-inline-end: 0;
  transform: translate(0, calc(100% + var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='bottom-center'] {
  inset-block-end: 0;
  inset-inline-start: 50%;
  transform: translate(-50%, calc(100% + var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='bottom-left'] {
  inset-block-end: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(100% + var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='left-middle'] {
  inset-block-start: 50%;
  inset-inline-start: 0;
  transform: translate(calc(-100% - var(--ck-locale-switcher-gap)), -50%);
}

.ck-locale-switcher[data-host='stage'][data-position='top-left'] {
  inset-block-start: var(--space-3);
  inset-inline-start: var(--space-3);
}

.ck-locale-switcher[data-host='stage'][data-position='top-center'] {
  inset-block-start: var(--space-3);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-locale-switcher[data-host='stage'][data-position='top-right'] {
  inset-block-start: var(--space-3);
  inset-inline-end: var(--space-3);
}

.ck-locale-switcher[data-host='stage'][data-position='right-middle'] {
  inset-block-start: 50%;
  inset-inline-end: var(--space-3);
  transform: translateY(-50%);
}

.ck-locale-switcher[data-host='stage'][data-position='bottom-right'] {
  inset-block-end: var(--space-3);
  inset-inline-end: var(--space-3);
}

.ck-locale-switcher[data-host='stage'][data-position='bottom-center'] {
  inset-block-end: var(--space-3);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-locale-switcher[data-host='stage'][data-position='bottom-left'] {
  inset-block-end: var(--space-3);
  inset-inline-start: var(--space-3);
}

.ck-locale-switcher[data-host='stage'][data-position='left-middle'] {
  inset-block-start: 50%;
  inset-inline-start: var(--space-3);
  transform: translateY(-50%);
}

.ck-locale-switcher__select {
  appearance: none;
  display: inline-flex;
  inline-size: 100%;
  min-inline-size: 0;
  padding-block: var(--ck-locale-switcher-padding-block, 10px);
  padding-inline: var(--ck-locale-switcher-padding-inline, 14px);
  padding-inline-end: calc(var(--ck-locale-switcher-padding-inline, 14px) + 24px);
  border-radius: var(--ck-locale-switcher-radius, var(--control-radius-md));
  border: var(--ck-locale-switcher-border-width, 1px) solid
    var(--ck-locale-switcher-border-color, transparent);
  background:
    var(--ck-locale-switcher-arrow, none) no-repeat right 10px center / 14px 14px,
    var(--ck-locale-switcher-bg, var(--color-system-white));
  color: inherit;
  font-family: var(--typo-locale-switcher-family, var(--font-ui));
  font-style: var(--typo-locale-switcher-style, normal);
  font-weight: var(--typo-locale-switcher-weight, 600);
  font-size: var(--typo-locale-switcher-size, var(--fs-14));
  letter-spacing: var(--typo-locale-switcher-tracking, 0em);
  line-height: var(--typo-locale-switcher-line-height, var(--lh-tight));
  box-shadow: none;
  cursor: pointer;
}

.ck-locale-switcher__select:focus-visible {
  outline: 2px solid color-mix(in oklab, currentColor, transparent 72%);
  outline-offset: 2px;
}

/* ck-style-module:end */

/* ck-style-module:shared-stagePod.css */
:root,
html,
body {
  height: 100%;
}

body {
  margin: 0;
  padding: 0;
  background: transparent;
  color: var(--color-system-black);
  font: 400 var(--fs-14)/var(--lh-body) var(--font-ui);
}

.stage {
  width: 100%;
  background: var(--stage-bg, transparent);
  box-shadow: var(--stage-shadow, none);
  display: flex;
  justify-content: center;
  align-items: flex-start;
  box-sizing: border-box;
  min-height: auto;
  padding: var(--stage-pad-desktop-top, 0) var(--stage-pad-desktop-right, 0)
    var(--stage-pad-desktop-bottom, 0) var(--stage-pad-desktop-left, 0);
}

.stage[data-canvas-mode='viewport'] {
  min-height: 100vh;
}

.stage[data-canvas-mode='fixed'] {
  width: var(--stage-fixed-width, auto);
  height: var(--stage-fixed-height, auto);
  margin-inline: auto;
}

.stage[data-layout-position='top-bar'],
.stage[data-layout-position='bottom-bar'] {
  position: fixed;
  inset-inline: 0;
  z-index: 1000;
}

.stage[data-layout-position='top-bar'] {
  inset-block-start: 0;
}

.stage[data-layout-position='bottom-bar'] {
  inset-block-end: 0;
}

.stage[data-layout-position='full-width'],
.stage[data-layout-position='top-bar'],
.stage[data-layout-position='bottom-bar'],
.stage[data-layout-position='static-top'] {
  width: 100%;
}

@media (max-width: 900px) {
  .stage {
    padding: var(--stage-pad-mobile-top, var(--stage-pad-desktop-top, 0))
      var(--stage-pad-mobile-right, var(--stage-pad-desktop-right, 0))
      var(--stage-pad-mobile-bottom, var(--stage-pad-desktop-bottom, 0))
      var(--stage-pad-mobile-left, var(--stage-pad-desktop-left, 0));
  }
}

.pod {
  width: auto;
  container-type: inline-size;
  background: var(--pod-bg, transparent);
  padding: var(--pod-pad-desktop-top, 0) var(--pod-pad-desktop-right, 0)
    var(--pod-pad-desktop-bottom, 0) var(--pod-pad-desktop-left, 0);
  border: var(--pod-border-width, 0px) solid var(--pod-border-color, transparent);
  box-shadow: var(--pod-shadow, none);
  border-radius: var(--pod-radius, var(--control-radius-lg));
  box-sizing: border-box;
  margin: 0;
}

@media (max-width: 900px) {
  .pod {
    padding: var(--pod-pad-mobile-top, var(--pod-pad-desktop-top, 0))
      var(--pod-pad-mobile-right, var(--pod-pad-desktop-right, 0))
      var(--pod-pad-mobile-bottom, var(--pod-pad-desktop-bottom, 0))
      var(--pod-pad-mobile-left, var(--pod-pad-desktop-left, 0));
  }
}

.pod[data-width-mode='wrap'] {
  width: auto;
  max-width: var(--content-width, 960px);
}

.pod[data-width-mode='fixed'] {
  width: 100%;
  max-width: var(--content-width, 960px);
}

.pod[data-width-mode='full'] {
  width: 100%;
  max-width: 100%;
}

[data-ck-widget],
.ck-headerLayout,
.ck-headerLayout__body {
  min-width: 0;
  max-width: 100%;
}

[data-ck-widget]
  :where(
    h1,
    h2,
    h3,
    h4,
    h5,
    h6,
    [role='heading'],
    [data-role$='title'],
    [data-role$='headline'],
    [data-role$='statement'],
    [data-role$='question-text']
  ) {
  overflow-wrap: break-word;
  word-break: normal;
  text-wrap: balance;
}

[data-ck-widget]
  :where(
    [data-role$='subtitle'],
    [data-role$='eyebrow'],
    [data-role$='support'],
    [data-role$='supporting-text'],
    [data-role$='copy'],
    [data-role$='answer'],
    [data-role$='label'],
    [data-role$='caption'],
    [data-role$='section-title']
  ) {
  overflow-wrap: break-word;
  word-break: normal;
}

[data-ck-widget] :where(a, button, [data-role$='cta'], [data-role$='action']) {
  max-width: 100%;
  min-width: 0;
  white-space: normal;
  text-align: center;
  overflow-wrap: break-word;
}

/* ck-style-module:end */

/* ck-style-module:shared-socialShare.css */
.ck-socialShare {
  box-sizing: border-box;
}

.ck-socialShare {
  position: absolute;
  z-index: 80;
  color: var(--color-system-black, #111);
  font-family: var(--font-ui, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif);
}

.ck-socialShare[data-host='pod'] {
  --ck-social-share-gap: var(--space-3, 12px);
}

.ck-socialShare[data-host='stage'] {
  --ck-social-share-gap: var(--space-4, 16px);
}

.ck-socialShare[data-host='pod'][data-position='top-left'] {
  inset-block-start: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(-100% - var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='top-center'] {
  inset-block-start: 0;
  inset-inline-start: 50%;
  transform: translate(-50%, calc(-100% - var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='top-right'] {
  inset-block-start: 0;
  inset-inline-end: 0;
  transform: translate(0, calc(-100% - var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='right-middle'] {
  inset-block-start: 50%;
  inset-inline-end: 0;
  transform: translate(calc(100% + var(--ck-social-share-gap)), -50%);
}

.ck-socialShare[data-host='pod'][data-position='bottom-right'] {
  inset-block-end: 0;
  inset-inline-end: 0;
  transform: translate(0, calc(100% + var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='bottom-center'] {
  inset-block-end: 0;
  inset-inline-start: 50%;
  transform: translate(-50%, calc(100% + var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='bottom-left'] {
  inset-block-end: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(100% + var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='left-middle'] {
  inset-block-start: 50%;
  inset-inline-start: 0;
  transform: translate(calc(-100% - var(--ck-social-share-gap)), -50%);
}

.ck-socialShare[data-host='stage'][data-position='top-left'] {
  inset-block-start: var(--ck-social-share-gap);
  inset-inline-start: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='top-center'] {
  inset-block-start: var(--ck-social-share-gap);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-socialShare[data-host='stage'][data-position='top-right'] {
  inset-block-start: var(--ck-social-share-gap);
  inset-inline-end: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='right-middle'] {
  inset-block-start: 50%;
  inset-inline-end: var(--ck-social-share-gap);
  transform: translateY(-50%);
}

.ck-socialShare[data-host='stage'][data-position='bottom-right'] {
  inset-block-end: var(--ck-social-share-gap);
  inset-inline-end: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='bottom-center'] {
  inset-block-end: var(--ck-social-share-gap);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-socialShare[data-host='stage'][data-position='bottom-left'] {
  inset-block-end: var(--ck-social-share-gap);
  inset-inline-start: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='left-middle'] {
  inset-block-start: 50%;
  inset-inline-start: var(--ck-social-share-gap);
  transform: translateY(-50%);
}

.ck-socialShare:hover .ck-socialShare__topbar,
.ck-socialShare[data-ck-preview="true"] .ck-socialShare__topbar,
.ck-socialShare:focus-within .ck-socialShare__topbar {
  opacity: 1;
}

@media (hover: none) {
  .ck-socialShare__topbar {
    opacity: 1;
  }
}

.ck-socialShare__topbar {
  display: flex;
  justify-content: flex-end;
  opacity: 0;
  transition: opacity var(--duration-base, 160ms);
}

.ck-socialShare__details {
  position: relative;
}

.ck-socialShare__button {
  list-style: none;
  min-height: 42px;
  display: inline-flex;
  align-items: center;
  gap: var(--control-inline-gap-sm, 8px);
  padding: 0 15px;
  border-radius: var(--control-radius-lg, 12px);
  border: 1px solid color-mix(in oklab, var(--color-system-white, #fff), transparent 84%);
  background: color-mix(in oklab, var(--color-system-black, #000) 80%, transparent);
  color: var(--color-system-white, #fff);
  font: 600 var(--fs-13, 13px)/1.1 var(--font-ui, system-ui);
  cursor: pointer;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

.ck-socialShare__button::-webkit-details-marker {
  display: none;
}

.ck-socialShare__button::marker {
  content: "";
}

.ck-socialShare__button:hover {
  background: color-mix(in oklab, var(--color-system-black, #000) 86%, transparent);
}

.ck-socialShare__button:focus-visible,
.ck-socialShare__card:focus-visible {
  outline: var(--focus-ring-width, 2px) solid var(--color-system-blue, #1c7cff);
  outline-offset: 2px;
}

.ck-socialShare__icon {
  display: inline-flex;
  width: 20px;
  height: 20px;
  align-items: center;
  justify-content: center;
  color: currentColor;
}

.ck-socialShare__icon svg {
  width: 20px;
  height: 20px;
  display: block;
  color: currentColor;
}

.ck-socialShare__icon svg [stroke] {
  stroke: currentColor;
}

.ck-socialShare__icon svg [fill] {
  fill: currentColor;
}

.ck-socialShare__menu {
  position: absolute;
  top: calc(100% + var(--space-3, 12px));
  right: 0;
  width: min(760px, calc(100vw - 32px));
  max-height: min(520px, calc(100vh - 120px));
  overflow: auto;
  display: none;
  padding: 16px;
  border-radius: var(--control-radius-2xl, 20px);
  border: 1px solid color-mix(in oklab, var(--color-system-black, #000), transparent 90%);
  background: color-mix(in oklab, var(--color-system-white, #fff), transparent 8%);
  box-shadow: 0 28px 90px color-mix(in oklab, var(--color-system-black, #000), transparent 86%);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
}

.ck-socialShare__details[open] .ck-socialShare__menu {
  display: block;
}

.ck-socialShare__section[hidden] {
  display: none !important;
}

.ck-socialShare__section + .ck-socialShare__section {
  margin-top: var(--space-5, 20px);
}

.ck-socialShare__sectionTitle {
  margin: 10px 6px var(--space-3, 12px);
  color: var(--color-system-black, #111);
  font: 700 var(--fs-13, 13px)/1.1 var(--font-ui, system-ui);
  text-transform: uppercase;
  white-space: nowrap;
}

.ck-socialShare__grid {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: var(--space-2, 8px);
  margin-bottom: 0;
}

.ck-socialShare__card {
  min-height: 88px;
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 16px 10px;
  border: 0;
  border-radius: var(--control-radius-xl, 16px);
  background: var(--color-system-gray-5-step4, color-mix(in oklab, var(--color-system-black, #000) 6%, transparent));
  color: var(--color-system-black, #111);
  cursor: pointer;
  text-align: center;
  transition:
    background-color var(--duration-base, 160ms),
    color var(--duration-base, 160ms),
    transform var(--duration-base, 160ms);
}

.ck-socialShare__card:hover {
  color: var(--color-system-blue, #1c7cff);
  background: color-mix(
    in oklab,
    var(--color-system-gray-5-step4, color-mix(in oklab, var(--color-system-black, #000) 6%, transparent)),
    var(--color-system-black, #000) 8%
  );
}

.ck-socialShare__card:active {
  transform: translateY(1px);
}

.ck-socialShare__cardLabel {
  display: block;
  color: inherit;
  font: 500 var(--fs-13, 13px)/1.05 var(--font-ui, system-ui);
  text-wrap: balance;
}

.ck-socialShare__toast {
  position: absolute;
  top: calc(42px + var(--space-3, 12px));
  right: 0;
  z-index: 70;
  display: none;
  padding: 9px 12px;
  border-radius: var(--control-radius-lg, 12px);
  background: color-mix(in oklab, var(--color-system-white, #fff), transparent 25%);
  color: color-mix(in oklab, var(--color-system-black, #000), transparent 25%);
  font: 500 var(--fs-13, 13px)/1.2 var(--font-ui, system-ui);
  pointer-events: none;
  box-shadow: 0 20px 60px color-mix(in oklab, var(--color-system-black, #000), transparent 92%);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

@media (max-width: 720px) {
  .ck-socialShare[data-host='stage'] {
    --ck-social-share-gap: var(--space-3, 12px);
  }

  .ck-socialShare__menu {
    width: min(360px, calc(100vw - 24px));
    max-height: min(520px, calc(100vh - 96px));
  }

  .ck-socialShare__grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

/* ck-style-module:end */

/* ck-style-module:big-bang-widget-css */
.ck-bigBang-widget {
  width: 100%;
}

.ck-bigBang {
  width: 100%;
  background: transparent;
}

.ck-bigBang__core {
  width: 100%;
}

.ck-bigBang__content {
  max-width: var(--ck-bigBang-text-width, 880px);
  display: flex;
  flex-direction: column;
  gap: var(--ck-bigBang-gap, 24px);
}

.ck-bigBang__core[data-align="left"] .ck-bigBang__content {
  margin-right: auto;
  text-align: left;
}

.ck-bigBang__core[data-align="center"] .ck-bigBang__content {
  margin-inline: auto;
  text-align: center;
}

.ck-bigBang__statement,
.ck-bigBang__support {
  margin: 0;
}

.ck-bigBang__statement {
  color: var(--typo-bigBang-color, var(--color-system-black));
  font-family: var(--typo-bigBang-family, var(--font-ui));
  font-size: var(--typo-bigBang-size, 84px);
  font-style: var(--typo-bigBang-style, normal);
  font-weight: var(--typo-bigBang-weight, 800);
  letter-spacing: var(--typo-bigBang-tracking, 0em);
  line-height: var(--typo-bigBang-line-height, 0.94);
}

.ck-bigBang__support {
  max-width: min(720px, 100%);
  color: var(--typo-body-color, color-mix(in oklab, var(--color-system-black), transparent 28%));
  font-family: var(--typo-body-family, var(--font-ui));
  font-size: var(--typo-body-size, 20px);
  font-style: var(--typo-body-style, normal);
  font-weight: var(--typo-body-weight, 400);
  letter-spacing: var(--typo-body-tracking, 0em);
  line-height: var(--typo-body-line-height, 1.42);
}

.ck-bigBang__core[data-align="center"] .ck-bigBang__support {
  margin-inline: auto;
}

.ck-bigBang__support[hidden] {
  display: none;
}

@media (max-width: 700px) {
  .ck-bigBang__statement {
    line-height: var(--typo-bigBang-line-height, 1);
  }
}

/* ck-style-module:end */

