  margin-inline: 0 auto;
  text-align: left;
}

.ck-calltoaction__content[data-align='right'] {
  justify-items: end;
  margin-inline: auto 0;
  text-align: right;
}

.ck-calltoaction__text {
  display: grid;
  gap: calc(var(--ck-calltoaction-content-gap) * 0.55);
  max-width: 100%;
}

.ck-calltoaction__eyebrow,
.ck-calltoaction__headline,
.ck-calltoaction__supportingText {
  margin: 0;
}

.ck-calltoaction__eyebrow {
  font-family: var(--typo-eyebrow-family, var(--font-ui));
  font-style: var(--typo-eyebrow-style, normal);
  font-weight: var(--typo-eyebrow-weight, 700);
  font-size: var(--typo-eyebrow-size, var(--fs-13));
  letter-spacing: var(--typo-eyebrow-tracking, 0em);
  line-height: var(--typo-eyebrow-line-height, var(--lh-tight));
  color: var(--typo-eyebrow-color, var(--color-system-gray));
}

.ck-calltoaction__headline {
  font-family: var(--typo-title-family, var(--font-ui));
  font-style: var(--typo-title-style, normal);
  font-weight: var(--typo-title-weight, 700);
  font-size: var(--typo-title-size, var(--fs-44));
  letter-spacing: var(--typo-title-tracking, 0em);
  line-height: var(--typo-title-line-height, var(--lh-tight));
  color: var(--typo-title-color, var(--color-system-black));
}

.ck-calltoaction__supportingText {
  font-family: var(--typo-body-family, var(--font-ui));
  font-style: var(--typo-body-style, normal);
  font-weight: var(--typo-body-weight, 400);
  font-size: var(--typo-body-size, var(--fs-18));
  letter-spacing: var(--typo-body-tracking, 0em);
  line-height: var(--typo-body-line-height, var(--lh-body));
  color: var(--typo-body-color, var(--color-system-gray));
}

.ck-calltoaction__supportingText a {
  color: inherit;
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 2px;
}

.ck-calltoaction__action {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--control-inline-gap-sm, var(--space-2));
  max-width: 100%;
  padding-inline: var(--ck-calltoaction-action-padding-inline, var(--space-4));
  padding-block: max(var(--ck-calltoaction-action-padding-block, var(--space-3)), var(--space-2));
  border: var(--ck-calltoaction-action-border-width, 0px) solid var(--ck-calltoaction-action-border-color, transparent);
  border-radius: var(--ck-calltoaction-action-radius, var(--control-radius-md));
  background: var(--ck-calltoaction-action-bg, var(--color-system-blue));
  color: var(--ck-calltoaction-action-fg, var(--color-system-white));
  font-family: var(--typo-button-family, var(--font-ui));
  font-style: var(--typo-button-style, normal);
  font-weight: var(--typo-button-weight, 600);
  font-size: var(--typo-button-size, var(--fs-14));
  letter-spacing: var(--typo-button-tracking, 0em);
  line-height: var(--typo-button-line-height, var(--lh-tight));
  text-decoration: none;
  white-space: nowrap;
}

.ck-calltoaction__action[data-icon-placement='right'] {
  flex-direction: row-reverse;
}

.ck-calltoaction__actionIcon {
  display: inline-flex;
  flex: none;
  inline-size: var(--ck-calltoaction-action-icon-size, var(--icon-size-16, 1rem));
  block-size: var(--ck-calltoaction-action-icon-size, var(--icon-size-16, 1rem));
  background: currentColor;
  -webkit-mask-image: var(--ck-calltoaction-action-icon);
  mask-image: var(--ck-calltoaction-action-icon);
  -webkit-mask-position: center;
  mask-position: center;
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: contain;
  mask-size: contain;
}

.ck-calltoaction__action[aria-disabled='true'] {
  opacity: 0.55;
  pointer-events: none;
}

.ck-calltoaction__eyebrow[hidden],
.ck-calltoaction__supportingText[hidden],
.ck-calltoaction__action[hidden],
.ck-calltoaction__actionIcon[hidden] {
  display: none !important;
}

@media (max-width: 900px) {
  .ck-calltoaction__content {
    max-width: 100%;
  }

  .ck-calltoaction__action {
    white-space: normal;
  }
}

