cards.stylesCss:
/* ck-style-module:dieter-tokens-tokens.css */
@import "/dieter/tokens/tokens.css";
/* ck-style-module:end */

/* ck-style-module:dieter-components-button-button.css */
@import "/dieter/components/button/button.css";
/* ck-style-module:end */

/* ck-style-module:shared-header.css */
.ck-headerLayout {
  display: grid;
  gap: var(--ck-header-gap, var(--space-6));
}

.ck-headerLayout[data-has-header='false'] {
  grid-template-areas: 'body';
  gap: 0;
}

.ck-headerLayout[data-has-header='true'][data-header-placement='top'] {
  grid-template-areas:
    'header'
    'body';
}

.ck-headerLayout[data-has-header='true'][data-header-placement='bottom'] {
  grid-template-areas:
    'body'
    'header';
}

.ck-headerLayout[data-has-header='true'][data-header-placement='left'] {
  grid-template-columns: minmax(220px, 340px) minmax(0, 1fr);
  grid-template-areas: 'header body';
  align-items: start;
}

.ck-headerLayout[data-has-header='true'][data-header-placement='right'] {
  grid-template-columns: minmax(0, 1fr) minmax(220px, 340px);
  grid-template-areas: 'body header';
  align-items: start;
}

.ck-headerLayout > .ck-header {
  grid-area: header;
}

.ck-headerLayout > .ck-headerLayout__body {
  grid-area: body;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
}

.ck-header {
  display: grid;
  gap: var(--ck-header-inner-gap, var(--space-4));
}

.ck-header__text {
  display: flex;
  flex-direction: column;
  gap: var(--ck-header-text-gap, var(--space-2));
  min-width: 0;
}

.ck-header__title,
.ck-header__subtitle {
  margin: 0;
}

.ck-header__title {
  font-family: var(--typo-title-family, var(--font-ui));
  font-style: var(--typo-title-style, normal);
  font-weight: var(--typo-title-weight, 600);
  font-size: var(--typo-title-size, var(--fs-18));
  letter-spacing: var(--typo-title-tracking, 0em);
  line-height: var(--typo-title-line-height, var(--lh-tight));
  color: var(--typo-title-color, var(--color-system-black));
}

.ck-header__subtitle {
  font-family: var(--typo-body-family, var(--font-ui));
  font-style: var(--typo-body-style, normal);
  font-weight: var(--typo-body-weight, 400);
  font-size: var(--typo-body-size, var(--fs-14));
  letter-spacing: var(--typo-body-tracking, 0em);
  line-height: var(--typo-body-line-height, var(--lh-body));
  color: var(--typo-body-color, var(--color-system-black));
}

.ck-header__subtitle a {
  color: inherit;
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 2px;
}

.ck-header__subtitle[hidden] {
  display: none !important;
}

.ck-header[data-cta-placement='right'] {
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: center;
}

.ck-header[data-align='center'][data-cta-placement='right'] {
  grid-template-columns: auto auto;
  justify-content: center;
}

.ck-header[data-align='right'][data-cta-placement='right'] {
  grid-template-columns: auto auto;
  justify-content: end;
}

