      const initialLocale = runtimeContext.locale || '';
      applyState(runtimeContext.state, {
        ...runtimeContext,
        locale: initialLocale,
        instanceId: resolvedInstanceId,
      });
    }
  }

  runtime.register('cards', initCards);
})();

