.ck-socialShare__icon svg {
  width: 20px;
  height: 20px;
  display: block;
  color: currentColor;
}

.ck-socialShare__icon svg [stroke] {
  stroke: currentColor;
}

.ck-socialShare__icon svg [fill] {
  fill: currentColor;
}

.ck-socialShare__menu {
  position: absolute;
  top: calc(100% + var(--space-3, 12px));
  right: 0;
  width: min(760px, calc(100vw - 32px));
  max-height: min(520px, calc(100vh - 120px));
  overflow: auto;
  display: none;
  padding: 16px;
  border-radius: var(--control-radius-2xl, 20px);
  border: 1px solid color-mix(in oklab, var(--color-system-black, #000), transparent 90%);
  background: color-mix(in oklab, var(--color-system-white, #fff), transparent 8%);
  box-shadow: 0 28px 90px color-mix(in oklab, var(--color-system-black, #000), transparent 86%);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
}

.ck-socialShare__details[open] .ck-socialShare__menu {
  display: block;
}

.ck-socialShare__section[hidden] {
  display: none !important;
}

.ck-socialShare__section + .ck-socialShare__section {
  margin-top: var(--space-5, 20px);
}

.ck-socialShare__sectionTitle {
  margin: 10px 6px var(--space-3, 12px);
  color: var(--color-system-black, #111);
  font: 700 var(--fs-13, 13px)/1.1 var(--font-ui, system-ui);
  text-transform: uppercase;
  white-space: nowrap;
}

.ck-socialShare__grid {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: var(--space-2, 8px);
  margin-bottom: 0;
}

.ck-socialShare__card {
  min-height: 88px;
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 16px 10px;
  border: 0;
  border-radius: var(--control-radius-xl, 16px);
  background: var(--color-system-gray-5-step4, color-mix(in oklab, var(--color-system-black, #000) 6%, transparent));
  color: var(--color-system-black, #111);
  cursor: pointer;
  text-align: center;
  transition:
    background-color var(--duration-base, 160ms),
    color var(--duration-base, 160ms),
    transform var(--duration-base, 160ms);
}

.ck-socialShare__card:hover {
  color: var(--color-system-blue, #1c7cff);
  background: color-mix(
    in oklab,
    var(--color-system-gray-5-step4, color-mix(in oklab, var(--color-system-black, #000) 6%, transparent)),
    var(--color-system-black, #000) 8%
  );
}

.ck-socialShare__card:active {
  transform: translateY(1px);
}

.ck-socialShare__cardLabel {
  display: block;
  color: inherit;
  font: 500 var(--fs-13, 13px)/1.05 var(--font-ui, system-ui);
  text-wrap: balance;
}

.ck-socialShare__toast {
  position: absolute;
  top: calc(42px + var(--space-3, 12px));
  right: 0;
  z-index: 70;
  display: none;
  padding: 9px 12px;
  border-radius: var(--control-radius-lg, 12px);
  background: color-mix(in oklab, var(--color-system-white, #fff), transparent 25%);
  color: color-mix(in oklab, var(--color-system-black, #000), transparent 25%);
  font: 500 var(--fs-13, 13px)/1.2 var(--font-ui, system-ui);
  pointer-events: none;
  box-shadow: 0 20px 60px color-mix(in oklab, var(--color-system-black, #000), transparent 92%);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

@media (max-width: 720px) {
  .ck-socialShare[data-host='stage'] {
    --ck-social-share-gap: var(--space-3, 12px);
  }

  .ck-socialShare__menu {
    width: min(360px, calc(100vw - 24px));
    max-height: min(520px, calc(100vh - 96px));
  }

  .ck-socialShare__grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

/* ck-style-module:end */

/* ck-style-module:countdown-widget-css */
.ck-countdown-widget {
  --countdown-text-color: var(--color-system-black);
  --countdown-item-bg: var(--color-system-gray-6-step5);
  --countdown-cta-bg: var(--color-system-blue);
  --countdown-cta-bg-hover: color-mix(
    in oklab,
    var(--color-system-blue),
    var(--state-darken-target) var(--state-hover-mix)
  );
  --countdown-cta-outline: var(--color-system-blue);
  --countdown-cta-outline-hover: color-mix(
    in oklab,
    var(--color-system-blue),
    var(--state-lighten-target) var(--state-hover-mix)
  );
}

.ck-widget.ck-countdown-widget {
  box-sizing: border-box;
  width: 100%;
  max-width: 100%;
  padding: 0;
  border-radius: 0;
  background: transparent;
  box-shadow: none;
  border: 0;
  display: block;
}

.ck-countdown {
  --ck-header-gap: var(--space-4);
  width: 100%;
  background: transparent;
  box-sizing: border-box;
}

.ck-countdown__body {
  display: grid;
  gap: var(--space-4);
}

.ck-countdown[data-layout-align='left'] {
  --countdown-justify: flex-start;
  --countdown-text-align: left;
}

.ck-countdown[data-layout-align='center'] {
  --countdown-justify: center;
  --countdown-text-align: center;
}

.ck-countdown[data-layout-align='right'] {
  --countdown-justify: flex-end;
  --countdown-text-align: right;
}

.ck-countdown__timer {
  display: flex;
  align-items: center;
  justify-content: var(--countdown-justify, center);
  gap: var(--space-2);
  flex-wrap: wrap;
}

.ck-countdown__number {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-4) var(--space-5);
  background: var(--countdown-item-bg, var(--color-system-gray-5));
  border: var(--ck-cardwrapper-border-width, 0px) solid var(--ck-cardwrapper-border-color, transparent);
  box-shadow: var(--ck-cardwrapper-shadow, none);
  border-radius: var(--ck-cardwrapper-radius, var(--control-radius-md));
  min-width: 120px;
}

.ck-countdown__units {
  display: flex;
  align-items: center;
  justify-content: var(--countdown-justify, center);
  gap: var(--space-2);
  flex-wrap: wrap;
}

.ck-countdown__unit {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-width: 72px;
  padding: var(--space-3) var(--space-4);
  background: var(--countdown-item-bg, var(--color-system-gray-5));
  border: var(--ck-cardwrapper-border-width, 0px) solid var(--ck-cardwrapper-border-color, transparent);
  box-shadow: var(--ck-cardwrapper-shadow, none);
  border-radius: var(--ck-cardwrapper-radius, var(--control-radius-md));
}

.ck-countdown__separator {
  font-family: var(--typo-timer-family, var(--font-ui));
  font-size: var(--typo-timer-size, var(--fs-32));
  font-weight: var(--typo-timer-weight, 700);
  letter-spacing: var(--typo-timer-tracking, 0em);
  line-height: var(--typo-timer-line-height, 1);
  color: var(--typo-timer-color, var(--countdown-text-color));
}

.ck-countdown__value {
  font-family: var(--typo-timer-family, var(--font-ui));
  font-style: var(--typo-timer-style, normal);
  font-size: var(--typo-timer-size, var(--fs-32));
  font-weight: var(--typo-timer-weight, 700);
  letter-spacing: var(--typo-timer-tracking, 0em);
  line-height: var(--typo-timer-line-height, 1);
  color: var(--typo-timer-color, var(--countdown-text-color));
}

.ck-countdown__label {
  margin-top: var(--space-1);
  font-family: var(--typo-label-family, var(--font-ui));
  font-style: var(--typo-label-style, normal);
  font-size: var(--typo-label-size, var(--fs-12));
  font-weight: var(--typo-label-weight, 400);
  letter-spacing: var(--typo-label-tracking, 0em);
  line-height: var(--typo-label-line-height, var(--lh-tight));
  color: color-mix(in oklab, var(--typo-label-color, var(--countdown-text-color)), transparent 30%);
}

.ck-countdown[data-timer-style='inline'] .ck-countdown__units {
  gap: var(--space-2);
}

.ck-countdown[data-timer-style='inline'] .ck-countdown__unit {
  min-width: unset;
  padding: 0;
  background: transparent;
  border: none;
  box-shadow: none;
  border-radius: 0;
  flex-direction: row;
  align-items: baseline;
  gap: var(--space-1);
}

.ck-countdown[data-timer-style='inline'] .ck-countdown__label {
  margin-top: 0;
}

.ck-countdown[data-show-labels='false'] .ck-countdown__label {
  display: none !important;
}

.ck-countdown__actions {
  display: flex;
  justify-content: var(--countdown-justify, center);
}

.ck-countdown__cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-3) var(--space-5);
  border-radius: var(--control-radius-md);
  text-decoration: none;
  font-family: var(--typo-button-family, var(--font-ui));
  font-style: var(--typo-button-style, normal);
  font-size: var(--typo-button-size, var(--fs-14));
  font-weight: var(--typo-button-weight, 600);
  letter-spacing: var(--typo-button-tracking, 0em);
  line-height: var(--typo-button-line-height, var(--lh-tight));
  color: var(--typo-button-color, var(--color-system-white));
  background: var(--countdown-cta-bg);
  border: 1px solid var(--countdown-cta-bg);
  transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
}

.ck-countdown__cta:hover {
  background: var(--countdown-cta-bg-hover);
  border-color: var(--countdown-cta-bg-hover);
}

.ck-countdown__cta[data-variant='secondary'] {
  background: transparent;
  border-color: var(--countdown-cta-outline);
  color: var(--countdown-cta-outline);
}

.ck-countdown__cta[data-variant='secondary']:hover {
  background: var(--countdown-cta-outline-hover);
  border-color: var(--countdown-cta-outline-hover);
  color: var(--color-system-black);
}

.ck-countdown__after-message {
  display: flex;
  justify-content: var(--countdown-justify, center);
}

.ck-countdown__after-link {
  font-family: var(--typo-label-family, var(--font-ui));
  font-style: var(--typo-label-style, normal);
  font-size: var(--typo-label-size, var(--fs-12));
  font-weight: var(--typo-label-weight, 500);
  letter-spacing: var(--typo-label-tracking, 0em);
  line-height: var(--typo-label-line-height, var(--lh-tight));
  color: var(--typo-label-color, var(--countdown-text-color));
  text-decoration: none;
}

.ck-countdown__after-link:hover {
  text-decoration: underline;
}

[data-ck-widget='countdown'] [hidden] {
  display: none !important;
}

/* ck-style-module:end */

