  color: var(--ck-header-cta-fg, var(--color-system-white));
  border: var(--ck-header-cta-border-width, 0px) solid var(--ck-header-cta-border-color, transparent);
  text-decoration: none;
  font-family: var(--typo-button-family, var(--font-ui));
