  transform: translate(-50%, calc(100% + var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='bottom-left'] {
  inset-block-end: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(100% + var(--ck-locale-switcher-gap)));
}

.ck-locale-switcher[data-host='pod'][data-position='left-middle'] {
