  inset-inline-start: 0;
  transform: translate(calc(-100% - var(--ck-locale-switcher-gap)), -50%);
}

.ck-locale-switcher[data-host='stage'][data-position='top-left'] {
  inset-block-start: var(--space-3);
  inset-inline-start: var(--space-3);
}

.ck-locale-switcher[data-host='stage'][data-position='top-center'] {
  inset-block-start: var(--space-3);
