.ck-locale-switcher[data-host='stage'][data-position='bottom-right'] {
  inset-block-end: var(--space-3);
  inset-inline-end: var(--space-3);
}

.ck-locale-switcher[data-host='stage'][data-position='bottom-center'] {
  inset-block-end: var(--space-3);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-locale-switcher[data-host='stage'][data-position='bottom-left'] {
  inset-block-end: var(--space-3);
  inset-inline-start: var(--space-3);
