  font-style: var(--typo-section-style, normal);
  font-weight: var(--typo-section-weight, 600);
  font-size: var(--typo-section-size, var(--fs-14));
  letter-spacing: var(--typo-section-tracking, 0em);
  line-height: var(--typo-section-line-height, var(--lh-tight));
  color: var(--typo-section-color);
}

.ck-faq__item {
  position: relative;
  border-radius: var(--ck-cardwrapper-radius, var(--control-radius-lg));
  border: var(--ck-cardwrapper-border-width) solid var(--ck-cardwrapper-border-color);
  background: var(--faq-item-bg, var(--color-system-gray-6-step5));
  box-shadow: var(--ck-cardwrapper-shadow);
  overflow: hidden;
  padding: var(--faq-item-pad-top, var(--space-3)) var(--faq-item-pad-right, var(--space-4))
    var(--faq-item-pad-bottom, var(--space-3)) var(--faq-item-pad-left, var(--space-4));
}

.ck-faq__q {
  width: 100%;
  text-align: left;
  padding: 0;
  background: none;
  border: 0;
  cursor: pointer;
  font-family: var(--typo-question-family, var(--font-ui));
  font-style: var(--typo-question-style, normal);
  font-size: var(--typo-question-size, var(--faq-question-size, var(--fs-14)));
  font-weight: var(--typo-question-weight, 500);
  letter-spacing: var(--typo-question-tracking, 0em);
  line-height: var(--typo-question-line-height, var(--lh-tight));
  color: var(--typo-question-color);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-2);
}

.ck-faq__q-text {
  font-family: var(--typo-question-family, var(--font-ui));
  font-style: var(--typo-question-style, normal);
  font-size: var(--typo-question-size, var(--faq-question-size, var(--fs-14)));
  font-weight: var(--typo-question-weight, 500);
  letter-spacing: var(--typo-question-tracking, 0em);
}

.ck-faq__q-icon.diet-btn-ic {
  flex: none;
  --btn-color: var(--faq-icon-color, var(--color-system-gray-2));
}

.ck-faq__q-icon .diet-btn-ic__icon {
  background-color: currentColor;
  /* Default to same-origin Dieter icons. Runtime may override via --faq-icon-expand/--faq-icon-collapse. */
  -webkit-mask-image: var(--faq-icon-expand, url("/dieter/icons/svg/plus.svg"));
  mask-image: var(--faq-icon-expand, url("/dieter/icons/svg/plus.svg"));
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-position: center;
  mask-position: center;
  -webkit-mask-size: contain;
  mask-size: contain;
}

.ck-faq__q[aria-expanded='true'] .ck-faq__q-icon .diet-btn-ic__icon {
  -webkit-mask-image: var(--faq-icon-collapse, url("/dieter/icons/svg/minus.svg"));
  mask-image: var(--faq-icon-collapse, url("/dieter/icons/svg/minus.svg"));
}

