.ck-faq[data-layout='multicolumn'] .ck-faq__q {
  cursor: default;
  padding-bottom: 0;
  background: transparent;
}

.ck-faq[data-layout='list'] .ck-faq__q-icon,
.ck-faq[data-layout='multicolumn'] .ck-faq__q-icon {
  display: none;
}

.ck-faq[data-layout='list'] .ck-faq__a,
.ck-faq[data-layout='multicolumn'] .ck-faq__a {
  display: block;
  padding-top: 0;
}

.ck-faq__a {
  font: var(--typo-answer-weight, 400)
    var(--typo-answer-size, var(--faq-answer-size, var(--fs-14)))
    / var(--typo-answer-line-height, var(--lh-body))
    var(--typo-answer-family, var(--font-ui));
  font-style: var(--typo-answer-style, normal);
  letter-spacing: var(--typo-answer-tracking, 0em);
}

.ck-faq[data-layout='multicolumn'] .ck-faq__q {
  border-bottom: 0;
  padding-bottom: 0;
}

.ck-faq[data-layout='list'] {
  --ck-cardwrapper-border-color: var(--color-system-gray-5);
}

.ck-faq[data-layout='multicolumn'] {
  --ck-cardwrapper-border-color: color-mix(in oklab, var(--color-system-gray-4), transparent 20%);
}

.ck-faq[data-layout='list'] .ck-faq__item {
  background: var(--faq-item-bg, var(--color-system-gray-6-step5));
}

.ck-faq[data-layout='multicolumn'] .ck-faq__item {
  background: var(--faq-item-bg, var(--color-system-white));
}

.ck-faq__a {
  padding: 0;
  margin-top: var(--faq-qa-gap, var(--space-2));
  color: var(--typo-answer-color);
  display: none;
}

.ck-faq__q[aria-expanded='true'] + .ck-faq__a {
  display: block;
}

.ck-faq__q-text a,
.ck-faq__a a {
  cursor: pointer;
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--faq-link-underline-color);
  text-decoration-thickness: 1px;
  text-underline-offset: 0.15em;
}

.ck-faq[data-link-style='color'] .ck-faq__q-text a,
.ck-faq[data-link-style='color'] .ck-faq__a a {
  color: var(--faq-link-text-color);
  text-decoration: none;
}

.ck-faq[data-link-style='highlight'] .ck-faq__q-text a,
.ck-faq[data-link-style='highlight'] .ck-faq__a a {
  text-decoration: none;
  background: var(--faq-link-highlight-color);
  border-radius: var(--control-radius-sm);
  padding: 0 0.16em;
  box-decoration-break: clone;
  -webkit-box-decoration-break: clone;
}

.ck-faq__a img.ck-faq__a-img {
  max-width: 100%;
  border-radius: var(--control-radius-md);
  margin: var(--space-2) 0;
}

.ck-faq__a-video {
  position: relative;
  padding-top: 56.25%;
  margin: var(--space-2) 0;
  border-radius: var(--control-radius-md);
  overflow: hidden;
}

.ck-faq__a-video iframe {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  border: 0;
}

.ck-faq__empty,
.ck-faq__noresults {
  padding: var(--space-3);
  border-radius: var(--control-radius-md);
  background: var(--color-system-gray-6-step5);
  color: var(--color-system-gray-2);
  font: 500 var(--fs-13)/var(--lh-body) var(--font-ui);
}

.ck-faq[data-layout='multicolumn'] .ck-faq__list {
  grid-template-columns: repeat(var(--faq-columns-desktop, 2), minmax(0, 1fr));
  align-items: start;
}

/* Masonry uses CSS columns; visual order is column-first (top→bottom per column). */
.ck-faq[data-layout='multicolumn'][data-cards-layout='masonry'] .ck-faq__list {
  display: block;
  columns: var(--faq-columns-desktop, 2);
  column-gap: var(--layout-gap, var(--space-3));
}

.ck-faq[data-layout='multicolumn'][data-cards-layout='masonry'] .ck-faq__item {
  break-inside: avoid;
  -webkit-column-break-inside: avoid;
  display: block;
  box-sizing: border-box;
  margin: 0 0 var(--layout-gap, var(--space-3));
}

@media (max-width: 900px) {
  .ck-faq[data-layout='multicolumn'] .ck-faq__list {
    grid-template-columns: repeat(var(--faq-columns-mobile, 1), minmax(0, 1fr));
  }

  .ck-faq[data-layout='multicolumn'][data-cards-layout='masonry'] .ck-faq__list {
    columns: var(--faq-columns-mobile, 1);
  }
}

