  grid-area: header;
}

.ck-headerLayout > .ck-headerLayout__body {
  grid-area: body;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
}

.ck-header {
  display: grid;
  gap: var(--ck-header-inner-gap, var(--space-4));
}

.ck-header__text {
  display: flex;
  flex-direction: column;
  gap: var(--ck-header-text-gap, var(--space-2));
