  padding-block: max(var(--ck-header-cta-padding-block, var(--space-3)), var(--space-2));
  border-radius: var(--ck-header-cta-radius, var(--control-radius-md));
  background: var(--ck-header-cta-bg, var(--color-system-blue));
  color: var(--ck-header-cta-fg, var(--color-system-white));
