  padding-block: var(--ck-locale-switcher-padding-block, 10px);
  padding-inline: var(--ck-locale-switcher-padding-inline, 14px);
  padding-inline-end: calc(var(--ck-locale-switcher-padding-inline, 14px) + 24px);
  border-radius: var(--ck-locale-switcher-radius, var(--control-radius-md));
  border: var(--ck-locale-switcher-border-width, 1px) solid
    var(--ck-locale-switcher-border-color, transparent);
  background:
    var(--ck-locale-switcher-arrow, none) no-repeat right 10px center / 14px 14px,
    var(--ck-locale-switcher-bg, var(--color-system-white));
  color: inherit;
  font-family: var(--typo-locale-switcher-family, var(--font-ui));
  font-style: var(--typo-locale-switcher-style, normal);
  font-weight: var(--typo-locale-switcher-weight, 600);
  font-size: var(--typo-locale-switcher-size, var(--fs-14));
  letter-spacing: var(--typo-locale-switcher-tracking, 0em);
  line-height: var(--typo-locale-switcher-line-height, var(--lh-tight));
  box-shadow: none;
  cursor: pointer;
}

.ck-locale-switcher__select:focus-visible {
  outline: 2px solid color-mix(in oklab, currentColor, transparent 72%);
  outline-offset: 2px;
}

/* ck-style-module:end */

/* ck-style-module:shared-stagePod.css */
:root,
html,
body {
  height: 100%;
}

body {
  margin: 0;
  padding: 0;
  background: transparent;
  color: var(--color-system-black);
  font: 400 var(--fs-14)/var(--lh-body) var(--font-ui);
}

.stage {
  width: 100%;
  background: var(--stage-bg, transparent);
  box-shadow: var(--stage-shadow, none);
  display: flex;
  justify-content: center;
  align-items: flex-start;
  box-sizing: border-box;
  min-height: auto;
  padding: var(--stage-pad-desktop-top, 0) var(--stage-pad-desktop-right, 0)
    var(--stage-pad-desktop-bottom, 0) var(--stage-pad-desktop-left, 0);
}

.stage[data-canvas-mode='viewport'] {
  min-height: 100vh;
}

.stage[data-canvas-mode='fixed'] {
  width: var(--stage-fixed-width, auto);
  height: var(--stage-fixed-height, auto);
  margin-inline: auto;
}

.stage[data-layout-position='top-bar'],
.stage[data-layout-position='bottom-bar'] {
  position: fixed;
  inset-inline: 0;
  z-index: 1000;
}

.stage[data-layout-position='top-bar'] {
  inset-block-start: 0;
}

.stage[data-layout-position='bottom-bar'] {
  inset-block-end: 0;
}

.stage[data-layout-position='full-width'],
.stage[data-layout-position='top-bar'],
.stage[data-layout-position='bottom-bar'],
.stage[data-layout-position='static-top'] {
  width: 100%;
}

@media (max-width: 900px) {
  .stage {
    padding: var(--stage-pad-mobile-top, var(--stage-pad-desktop-top, 0))
      var(--stage-pad-mobile-right, var(--stage-pad-desktop-right, 0))
      var(--stage-pad-mobile-bottom, var(--stage-pad-desktop-bottom, 0))
      var(--stage-pad-mobile-left, var(--stage-pad-desktop-left, 0));
  }
}

.pod {
  width: auto;
  container-type: inline-size;
  background: var(--pod-bg, transparent);
  padding: var(--pod-pad-desktop-top, 0) var(--pod-pad-desktop-right, 0)
    var(--pod-pad-desktop-bottom, 0) var(--pod-pad-desktop-left, 0);
  border: var(--pod-border-width, 0px) solid var(--pod-border-color, transparent);
  box-shadow: var(--pod-shadow, none);
  border-radius: var(--pod-radius, var(--control-radius-lg));
  box-sizing: border-box;
  margin: 0;
}

@media (max-width: 900px) {
  .pod {
    padding: var(--pod-pad-mobile-top, var(--pod-pad-desktop-top, 0))
      var(--pod-pad-mobile-right, var(--pod-pad-desktop-right, 0))
      var(--pod-pad-mobile-bottom, var(--pod-pad-desktop-bottom, 0))
      var(--pod-pad-mobile-left, var(--pod-pad-desktop-left, 0));
  }
}

.pod[data-width-mode='wrap'] {
  width: auto;
  max-width: var(--content-width, 960px);
}

.pod[data-width-mode='fixed'] {
  width: 100%;
  max-width: var(--content-width, 960px);
}

.pod[data-width-mode='full'] {
  width: 100%;
  max-width: 100%;
}

[data-ck-widget],
.ck-headerLayout,
.ck-headerLayout__body {
  min-width: 0;
  max-width: 100%;
}

[data-ck-widget]
  :where(
    h1,
    h2,
    h3,
    h4,
    h5,
    h6,
    [role='heading'],
    [data-role$='title'],
    [data-role$='headline'],
    [data-role$='statement'],
    [data-role$='question-text']
  ) {
  overflow-wrap: break-word;
  word-break: normal;
  text-wrap: balance;
}

[data-ck-widget]
  :where(
    [data-role$='subtitle'],
    [data-role$='eyebrow'],
    [data-role$='support'],
    [data-role$='supporting-text'],
    [data-role$='copy'],
    [data-role$='answer'],
    [data-role$='label'],
    [data-role$='caption'],
    [data-role$='section-title']
  ) {
  overflow-wrap: break-word;
  word-break: normal;
}

[data-ck-widget] :where(a, button, [data-role$='cta'], [data-role$='action']) {
  max-width: 100%;
  min-width: 0;
  white-space: normal;
  text-align: center;
  overflow-wrap: break-word;
}

/* ck-style-module:end */

/* ck-style-module:shared-socialShare.css */
.ck-socialShare {
  box-sizing: border-box;
}

.ck-socialShare {
  position: absolute;
  z-index: 80;
  color: var(--color-system-black, #111);
  font-family: var(--font-ui, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif);
}

.ck-socialShare[data-host='pod'] {
  --ck-social-share-gap: var(--space-3, 12px);
}

.ck-socialShare[data-host='stage'] {
  --ck-social-share-gap: var(--space-4, 16px);
}

.ck-socialShare[data-host='pod'][data-position='top-left'] {
  inset-block-start: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(-100% - var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='top-center'] {
  inset-block-start: 0;
  inset-inline-start: 50%;
  transform: translate(-50%, calc(-100% - var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='top-right'] {
  inset-block-start: 0;
  inset-inline-end: 0;
  transform: translate(0, calc(-100% - var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='right-middle'] {
  inset-block-start: 50%;
  inset-inline-end: 0;
  transform: translate(calc(100% + var(--ck-social-share-gap)), -50%);
}

.ck-socialShare[data-host='pod'][data-position='bottom-right'] {
  inset-block-end: 0;
  inset-inline-end: 0;
  transform: translate(0, calc(100% + var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='bottom-center'] {
  inset-block-end: 0;
  inset-inline-start: 50%;
  transform: translate(-50%, calc(100% + var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='bottom-left'] {
  inset-block-end: 0;
  inset-inline-start: 0;
  transform: translate(0, calc(100% + var(--ck-social-share-gap)));
}

.ck-socialShare[data-host='pod'][data-position='left-middle'] {
  inset-block-start: 50%;
  inset-inline-start: 0;
  transform: translate(calc(-100% - var(--ck-social-share-gap)), -50%);
}

.ck-socialShare[data-host='stage'][data-position='top-left'] {
  inset-block-start: var(--ck-social-share-gap);
  inset-inline-start: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='top-center'] {
  inset-block-start: var(--ck-social-share-gap);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-socialShare[data-host='stage'][data-position='top-right'] {
  inset-block-start: var(--ck-social-share-gap);
  inset-inline-end: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='right-middle'] {
  inset-block-start: 50%;
  inset-inline-end: var(--ck-social-share-gap);
  transform: translateY(-50%);
}

.ck-socialShare[data-host='stage'][data-position='bottom-right'] {
  inset-block-end: var(--ck-social-share-gap);
  inset-inline-end: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='bottom-center'] {
  inset-block-end: var(--ck-social-share-gap);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

.ck-socialShare[data-host='stage'][data-position='bottom-left'] {
  inset-block-end: var(--ck-social-share-gap);
  inset-inline-start: var(--ck-social-share-gap);
}

.ck-socialShare[data-host='stage'][data-position='left-middle'] {
  inset-block-start: 50%;
  inset-inline-start: var(--ck-social-share-gap);
  transform: translateY(-50%);
}

.ck-socialShare:hover .ck-socialShare__topbar,
.ck-socialShare[data-ck-preview="true"] .ck-socialShare__topbar,
.ck-socialShare:focus-within .ck-socialShare__topbar {
  opacity: 1;
}

@media (hover: none) {
  .ck-socialShare__topbar {
    opacity: 1;
  }
}

.ck-socialShare__topbar {
  display: flex;
  justify-content: flex-end;
  opacity: 0;
  transition: opacity var(--duration-base, 160ms);
}

.ck-socialShare__details {
  position: relative;
}

.ck-socialShare__button {
  list-style: none;
  min-height: 42px;
  display: inline-flex;
  align-items: center;
  gap: var(--control-inline-gap-sm, 8px);
  padding: 0 15px;
  border-radius: var(--control-radius-lg, 12px);
  border: 1px solid color-mix(in oklab, var(--color-system-white, #fff), transparent 84%);
  background: color-mix(in oklab, var(--color-system-black, #000) 80%, transparent);
  color: var(--color-system-white, #fff);
  font: 600 var(--fs-13, 13px)/1.1 var(--font-ui, system-ui);
  cursor: pointer;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

.ck-socialShare__button::-webkit-details-marker {
  display: none;
}

.ck-socialShare__button::marker {
  content: "";
}

.ck-socialShare__button:hover {
  background: color-mix(in oklab, var(--color-system-black, #000) 86%, transparent);
}

.ck-socialShare__button:focus-visible,
.ck-socialShare__card:focus-visible {
  outline: var(--focus-ring-width, 2px) solid var(--color-system-blue, #1c7cff);
  outline-offset: 2px;
}

.ck-socialShare__icon {
  display: inline-flex;
  width: 20px;
  height: 20px;
  align-items: center;
  justify-content: center;
  color: currentColor;
}

.ck-socialShare__icon svg {
  width: 20px;
  height: 20px;
  display: block;
  color: currentColor;
}

.ck-socialShare__icon svg [stroke] {
  stroke: currentColor;
}

.ck-socialShare__icon svg [fill] {
  fill: currentColor;
}

.ck-socialShare__menu {
  position: absolute;
  top: calc(100% + var(--space-3, 12px));
  right: 0;
  width: min(760px, calc(100vw - 32px));
  max-height: min(520px, calc(100vh - 120px));
  overflow: auto;
  display: none;
  padding: 16px;
  border-radius: var(--control-radius-2xl, 20px);
  border: 1px solid color-mix(in oklab, var(--color-system-black, #000), transparent 90%);
  background: color-mix(in oklab, var(--color-system-white, #fff), transparent 8%);
  box-shadow: 0 28px 90px color-mix(in oklab, var(--color-system-black, #000), transparent 86%);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
}

.ck-socialShare__details[open] .ck-socialShare__menu {
  display: block;
}

.ck-socialShare__section[hidden] {
  display: none !important;
}

.ck-socialShare__section + .ck-socialShare__section {
  margin-top: var(--space-5, 20px);
}

.ck-socialShare__sectionTitle {
  margin: 10px 6px var(--space-3, 12px);
  color: var(--color-system-black, #111);
  font: 700 var(--fs-13, 13px)/1.1 var(--font-ui, system-ui);
  text-transform: uppercase;
  white-space: nowrap;
}

.ck-socialShare__grid {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: var(--space-2, 8px);
  margin-bottom: 0;
}

.ck-socialShare__card {
  min-height: 88px;
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 16px 10px;
  border: 0;
  border-radius: var(--control-radius-xl, 16px);
  background: var(--color-system-gray-5-step4, color-mix(in oklab, var(--color-system-black, #000) 6%, transparent));
  color: var(--color-system-black, #111);
  cursor: pointer;
  text-align: center;
  transition:
    background-color var(--duration-base, 160ms),
    color var(--duration-base, 160ms),
    transform var(--duration-base, 160ms);
}

.ck-socialShare__card:hover {
  color: var(--color-system-blue, #1c7cff);
  background: color-mix(
    in oklab,
    var(--color-system-gray-5-step4, color-mix(in oklab, var(--color-system-black, #000) 6%, transparent)),
    var(--color-system-black, #000) 8%
  );
}

.ck-socialShare__card:active {
  transform: translateY(1px);
}

.ck-socialShare__cardLabel {
  display: block;
  color: inherit;
  font: 500 var(--fs-13, 13px)/1.05 var(--font-ui, system-ui);
  text-wrap: balance;
}

.ck-socialShare__toast {
  position: absolute;
  top: calc(42px + var(--space-3, 12px));
  right: 0;
  z-index: 70;
  display: none;
  padding: 9px 12px;
  border-radius: var(--control-radius-lg, 12px);
  background: color-mix(in oklab, var(--color-system-white, #fff), transparent 25%);
  color: color-mix(in oklab, var(--color-system-black, #000), transparent 25%);
  font: 500 var(--fs-13, 13px)/1.2 var(--font-ui, system-ui);
  pointer-events: none;
  box-shadow: 0 20px 60px color-mix(in oklab, var(--color-system-black, #000), transparent 92%);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

@media (max-width: 720px) {
  .ck-socialShare[data-host='stage'] {
    --ck-social-share-gap: var(--space-3, 12px);
  }

  .ck-socialShare__menu {
    width: min(360px, calc(100vw - 24px));
    max-height: min(520px, calc(100vh - 96px));
  }

  .ck-socialShare__grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

/* ck-style-module:end */

/* ck-style-module:split-carousel-media-widget-css */
.ck-split-carousel-media-widget,
.ck-split-carousel-media {
  width: 100%;
}

.ck-split-carousel-media__core {
  position: relative;
  min-width: 0;
  overflow: visible;
}

.ck-split-carousel-media__core[data-core-size-mode='auto'] {
  min-height: 320px;
  aspect-ratio: 16 / 9;
}

.ck-split-carousel-media__core[data-core-size-mode='fixed'] .ck-split-carousel-media__stage {
  height: 100%;
}

.ck-split-carousel-media__core[data-core-size-mode='responsive'] .ck-split-carousel-media__stage,
.ck-split-carousel-media__core[data-core-size-mode='responsive'] .ck-split-carousel-media__media,
.ck-split-carousel-media__core[data-core-size-mode='responsive'] .ck-split-carousel-media__media > img,
.ck-split-carousel-media__core[data-core-size-mode='responsive'] .ck-split-carousel-media__media > video {
  min-height: inherit;
}

.ck-split-carousel-media__stage {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: inherit;
  box-sizing: border-box;
  overflow: hidden;
  border: var(--ck-cardwrapper-border-width) solid var(--ck-cardwrapper-border-color);
  border-radius: var(--ck-cardwrapper-radius);
  box-shadow: var(--ck-cardwrapper-shadow);
}

.ck-split-carousel-media__media,
.ck-split-carousel-media__media > img,
.ck-split-carousel-media__media > video {
  width: 100%;
  height: 100%;
}

.ck-split-carousel-media__media[data-empty='true'] {
  background: color-mix(in oklab, var(--color-system-black), transparent 94%);
  display: grid;
  place-items: center;
}

.ck-split-carousel-media__media[data-empty='true']::before {
  content: '';
  inline-size: min(18%, 64px);
  aspect-ratio: 1;
  background: color-mix(in oklab, var(--color-system-black), transparent 72%);
  -webkit-mask: url('/dieter/icons/svg/photo.svg') center / contain no-repeat;
  mask: url('/dieter/icons/svg/photo.svg') center / contain no-repeat;
}

.ck-split-carousel-media__media {
  position: absolute;
  inset: 0;
  opacity: 0;
  pointer-events: none;
  transition: opacity 240ms ease, transform 280ms ease;
}

.ck-split-carousel-media__media[data-active='true'] {
  opacity: 1;
  pointer-events: auto;
}

.ck-split-carousel-media[data-transition='slide'] .ck-split-carousel-media__media {
  transform: translateX(18px);
}

.ck-split-carousel-media[data-transition='slide'] .ck-split-carousel-media__media[data-active='true'] {
  transform: translateX(0);
}

.ck-split-carousel-media__media > img,
.ck-split-carousel-media__media > video {
  display: block;
  object-fit: var(--ck-split-carousel-media-fit, cover);
  object-position: var(--ck-split-carousel-media-position, center);
}

.ck-split-carousel-media__control {
  position: absolute;
  top: 50%;
  z-index: 2;
  width: 40px;
  height: 40px;
  border: 1px solid color-mix(in oklab, var(--color-system-black), transparent 85%);
  border-radius: 999px;
  background: color-mix(in oklab, var(--color-system-white), transparent 10%);
  color: var(--color-system-black);
  transform: translateY(-50%);
  cursor: pointer;
}

.ck-split-carousel-media__control[data-dir='prev'] {
  left: 12px;
}

.ck-split-carousel-media__control[data-dir='next'] {
  right: 12px;
}

.ck-split-carousel-media__dots {
  position: absolute;
  left: 50%;
  bottom: 14px;
  z-index: 2;
  display: flex;
  gap: 8px;
  transform: translateX(-50%);
}

.ck-split-carousel-media__dot {
  width: 8px;
  height: 8px;
  border: 0;
  border-radius: 999px;
  background: color-mix(in oklab, var(--color-system-black), transparent 72%);
  cursor: pointer;
}

.ck-split-carousel-media__dot[aria-current='true'] {
  background: var(--color-system-black);
}

@media (max-width: 720px) {
  .ck-split-carousel-media__control {
    width: 36px;
    height: 36px;
  }
}

/* ck-style-module:end */

